 1	import * as React from "react";
 2	import { Button, Popover, PopoverPosition } from "@patternfly/react-core";
 3	
 4	type PopoverStatusProps = {
 5	  statusBody: React.ReactNode;
 6	  onHide?: () => void;
 7	  onShow?: () => void;
 8	  title?: string;
 9	  hideHeader?: boolean;
10	  isVisible?: boolean;
11	  shouldClose?: (hideFunction: unknown) => void;
12	};
13	
14	const PopoverStatus: React.FC<PopoverStatusProps> = ({
15	  hideHeader,
16	  children,
17	  isVisible = null,
18	  shouldClose = null,
19	  statusBody,
20	  title,
21	  onHide,
22	  onShow,
23	}) => {
24	  return (
25	    <Popover
26	      position={PopoverPosition.right}
27	      headerContent={hideHeader ? null : title}
28	      bodyContent={children}
29	      aria-label={title}
30	      onHide={onHide}
31	      onShow={onShow}
32	      isVisible={isVisible}
33	      shouldClose={shouldClose}
34	    >
35	      <Button variant="link" isInline>
36	        {statusBody}
37	      </Button>
38	    </Popover>
39	  );
40	};
41	
42	export default PopoverStatus;

